import{_ as r,H as o,o as p,c as n,k as e,a,L as i,V as s}from"./chunks/framework.410404a1.js";const P=JSON.parse('{"title":"夕拾散記×信宜中學","description":"不知不覺地，三年的光陰已悄然終去。反復看了看日曆，翻了又翻，才實確是與初中時代告別的時候了。","frontmatter":{"head":[["meta",{"name":"description","content":"不知不覺地，三年的光陰已悄然終去。反復看了看日曆，翻了又翻，才實確是與初中時代告別的時候了。"}],["meta",{"name":"keywords","content":"旅禾 夕拾散記 信宜中學 信中"}]]},"headers":[],"relativePath":"zh-HK/articles/夕拾散记×信宜中学.md","filePath":"zh-HK/articles/夕拾散记×信宜中学.md"}'),h={name:"zh-HK/articles/夕拾散记×信宜中学.md"},d=s('<h1 id="夕拾散記×信宜中學" tabindex="-1">夕拾散記×信宜中學 <a class="header-anchor" href="#夕拾散記×信宜中學" aria-label="Permalink to &quot;夕拾散記×信宜中學&quot;">​</a></h1><p>第1更 2023-06-30 發表於廣東</p><h2 id="_1-告別" tabindex="-1">1 告別 <a class="header-anchor" href="#_1-告別" aria-label="Permalink to &quot;1 告別&quot;">​</a></h2><p>不知不覺地，三年的光陰已悄然終去。反復看了看日曆，翻了又翻，才實確是與初中時代告別的時候了。</p><p>談到「告別」，就恍然地想起曾發表過的一篇講稿：『學會告別』。印象中文篇徵集時，我交過兩篇文章，一篇是寫得頗為認真的，再一篇則是胡亂湊數；但不知怎的，竟只有這篇價值正確但招搖撞騙的稿子被夾雜進了作文集裡，何不慚愧難當？</p><p>砍去文中的繁枝逸節，曾也提到，「只有臨風追趕，才有將自己的理想化之為實的可能」，也「不妨告別過去，去收穫新的未來」——但先讓我們等等，回歸文題。在本欄中，我們來淺覽下收拾了三年行旅來的大事小記的晾曬場；<strong>儘管過往並非事事稱心如意，但歡顏依然景景映於心中。</strong></p><h2 id="_2-校園景事篇" tabindex="-1">2 校園景事篇 <a class="header-anchor" href="#_2-校園景事篇" aria-label="Permalink to &quot;2 校園景事篇&quot;">​</a></h2><h3 id="壹" tabindex="-1">壹 <a class="header-anchor" href="#壹" aria-label="Permalink to &quot;壹&quot;">​</a></h3><p>邁入信中校門，先入眼簾的當是江梁瑞英樓與嵌上了兩片碧翠般園湖的前廣場，在東的是未名湖（南），在西的叫八〇湖。在夏日，校園的主色總會是綠，按宗璞的文筆來講：一進校門，綠色滿眼，猛然一涼，便把煩惱都拋在校門外了。</p><p>門邊東池的蓮荷總是繁盛的，而四下恰又水鏡空明光透澄漓，樓宇離遠而不致太甚，再疊上人煙較少，故對取景拍照愛好者莫不是個好去處。而在八〇湖，一棵白玉蘭占了半塘邊，校友捐贈的「狀元石」安立湖間；當然，亦有一小片蓮覆于池上，雖遠不若東池繁茂，但卻多有一兩朵淡粉透紅的蓮蓉。雖然兩池人跡鮮罕，但也正因如此，這裡可謂是校園一隅的清寧洞天——倘沒有鬼針草的伏擊與伏夏的炎熱應確如此。</p><p>校園裡的觀賞湖都鋪著石樁供行，湖中游魚和蝌蚪時而隱現。在江梁瑞英樓的北面則是令人熟近的園林與池橋，東邊的還是叫未名湖，西邊則為寶安湖：總算是要提到威武昂昂的校鴨之居地了。</p><p>到了未名湖的湖畔，這裡前不久建了一圈兔舍，一間茅蓋的鴨棚，旁立有曰「得舍」的石刻。這裡「得」之粵音諧「鴨」之英音，「舍」念去聲，故正看可作鴨舍；亦或倒作「捨得」，「舍」念上聲，此時可謂為一種取捨相結合的決策哲學。園中的小生靈，除了關在圍欄內的兔子，都自在逍遙地游竄在林水之間。拱木橋上望下，柳榕鴨松皆收目下，每至課餘就會有數群同學來到這裡賞鴨餵食，看它們結隊遊弋；另外園裡的一對白柔而有半人高（若計上兔耳的話）的兔子則顯得害羞不少，每每悄近時，就蹦著躥進屋裡了，惟僅露出茸長的耳朵，就挺活潑可愛的~！</p><p>西邊的寶安湖上縱橫著蜿折的石橋，來往于西運動場時就可去順路走走。寶安湖再往北，即是地理園。各式地貌模型、省市立體地形模型均置於此，進了地理園，路旁還有一大石制的地球儀，只可惜地理園年久失修，在年月風霜的銹蝕下也有了多多少少的損磨。</p><h3 id="貳" tabindex="-1">貳 <a class="header-anchor" href="#貳" aria-label="Permalink to &quot;貳&quot;">​</a></h3><p>校園的至東南側是東運動場和勵志園，再往北就是東教學樓（高三樓）了，高三樓北附著東自行車棚，車流來來往往；北邊是肖明實驗樓中的其中一座，現作初中部教學樓和部分物理實驗室：在這裡補充下介紹，肖明是信中的76屆校友、一名總建築師，參與了新校址很多建築的設計工作，在校園東南處修建的新教學樓亦出自他手。勵志園環繞著一片大湖，中央是假山與瀑布，假山腳旁稍遠處是一個涼亭，湖上石橋牽梭于數方間，高三樓就清晰而晰明地靜映在水上。</p><p>北邊是花壇與榮譽榜，東南處倒有個名為「江東讀書坊」的地方，一排排階梯上為一座石門，上書五字，再往裡就是後山區域了——對，沒錯，雖叫讀書坊，但實是校後山林的一處入口，坊門樣式類似於清華大學的二校門，或就是一座簡單的三拱牌坊。</p><p>勵志園西與南邊的是東運動場區，這裡應當是學校放課後除飯堂與宿舍外最熱門的區域了。今年二到三月，初中部在這裡進行了進行了XBL（信中籃聯）的決賽，現場激情撒揚，也拉開了初三最後一學期的序幕。當然，這裡也是體育節時的備訓地帶。</p><p>冬日裡曾在與東運動場相隔不遠的未名湖，蹲上數小時拍攝鴨子，可冷死了；下午的暖陽在未名湖上投下一片光亮，顯得沉穩而歡快。榕柳和茂密的灌木叢固守堤岸，鑲出一道綠錦條。幾隻校鴨撲拉拉掠過水面，遊至盡遠後再折返回來。</p><h3 id="三" tabindex="-1">三 <a class="header-anchor" href="#三" aria-label="Permalink to &quot;三&quot;">​</a></h3><p>再或是到西運動場，在東跑道的最東處紮根著一棵大榕樹（不得不說，在華南，榕樹無處不能種），在體育課時就時時在此乘涼。運動場內作足球場，戶外活動時這裡就會活躍著大群同學；在場內北邊是跳高場，再到跑道北就是乒乓球、秋千、爬杆、雙杠和實心球的天地了。</p><p>運動場西邊是體藝樓，學校最大的舞臺亦然於此，台後則有種類繁多的體育器材和乒乓球訓練場。這座舞臺或是在體育節時加油喝彩、或是在文化藝術節和最強音活動中承歌載演，總言之，至為繁鬧時，這裡無處不上映著全校同學的歡悅。</p><p>雖說在地圖裡一片空白，但在運動場的北上端，這裡可以看到一大片校外山坡的情景——雖然因此這裡的至北處被標明為地質災害區域，西車棚也在這片區中。在車棚中西望通透無垠（除了圍牆），可以俯覽城裡的千樓萬戶，挨著的是一片山坡；在三月中旬，曾為了準備初中化學自製pH試劑的材料，從校園東一路到校園西采材時，只見坡上滿山滿山的都是紫中綴白的牽牛花，在旁摘了數朵舂碎後浸上酒精，製成的指示劑是頗為好用的。</p><p>向東望去，劉軍樓旁校道邊栽著連片的鐵樹、鳳凰樹還有榕樹，直通到右廣場。右廣場四周是名人雕像，後圍襯著九裡香（在信中的花期一般為四到五月，花潔白而芳香逸遠，故此名），偉大的無產階級革命領袖毛主席的雕塑屹於路口處，佇望著前方。</p><p>右廣場的中央，環島週邊展示著各大高校的介紹牌。北邊則是精英樓（圖書館），覽閱館在右棟，是初一時傍晚常去之地，後時間表調整後就無暇再至了；學生發展指導與心理中心在中棟一樓，常年幫助同學們解決學習生活中的各種問題；左棟為文藝樓，晚上若在廣場旁即可聽到練琴聲蕩於校園之中，當然，還有美術生等等；在頂樓則是大型會議廳，除作各種公開會議活動外，還進行了初中部的第一二屆「用英語講中國故事」活動，部分文藝初演和合唱活動等。</p><p>在初三這年親自承制了英講活動的開場演講和組織流程，但不得不說：這片場地維護起來屬實是費時費力。不過同學們精心籌制的節目可謂是精彩絕倫，期待未來更多的創意呈現！</p><p>北上則至女舍旁的植物園，說是植物園，但看過之後更覺應是半片菜園了——折幾片南瓜葉或是番茄回去添菜！（當然沒有試過，注意下植物園裡的作物都淋灑過農藥，勿摘禁采）園中有葵花、仙人掌、高架上纏著的各色藤蔓，及園後架著簡木橋的池塘，美術寫生和心理活動皆曾在此。</p><h3 id="肆" tabindex="-1">肆 <a class="header-anchor" href="#肆" aria-label="Permalink to &quot;肆&quot;">​</a></h3><p>男舍的西邊則是飯堂，或信中學生大型情報交換中心，飯堂前廣場時時舉辦一些譬如義賣、樂會等等活動，九月開學季還會有社團招新哦！</p><p>肖明實驗樓C則是學校的化生實驗樓了，當然有時亦作考場，樓前的階梯旁和隔壁教室宿舍的北邊各有一棵木菠蘿樹，上不時結出大小不一的木菠蘿。教職工居住區下不時就有放學後的小朋友玩鬧，晚上在教室裡不時能聽見他們的逐嬉聲。</p><p>地圖右上角是一片空白，這是後山山路的入口之一。跑操或負責清潔工作時，就常常來往此地，跑操時就由此沿內環路繞湖而行。跑操時，若未聽錯的話，有時還能碰上山上吹拉民樂的師傅；在路上，往往歡樂的笑聲就會響徹山林。</p><h3 id="伍" tabindex="-1">伍 <a class="header-anchor" href="#伍" aria-label="Permalink to &quot;伍&quot;">​</a></h3><p>劉軍教學樓，作為信中高中部的教學樓之一，高一高二在此駐習。在信中的教學樓，每一位同學抬眼皆林景；而教學樓正側綠蔓與樹林交錯，樓道玻璃和專門設計的架子盡為青藤覆上。二樓中廳東有科創社團和課程錄播室，西側第二即為資訊競賽的培訓用室。二樓中廳北側是一處天臺園林，雖目測僅百餘平方米，但集眾於一身，到劉軍樓時不可錯過哦！</p><p>有時晚上在外面走——應該說，這種機會越來越少了——看見劉軍教學樓燈火通明，像一條夜航的大船，總會是十分興奮。<strong>那凝聚著教師與學生心血的智慧之光，就這樣一點點地，驅散著黑暗，啟發新的黎明。</strong></p>',33),c={id:"_3-校園軼事篇",tabindex:"-1"},l=e("a",{class:"header-anchor",href:"#_3-校園軼事篇","aria-label":'Permalink to "3 校園軼事篇<Badge type="warning" text="未完待續" />"'},"​",-1);function _(m,u,b,f,q,x){const t=o("Badge");return p(),n("div",null,[d,e("h2",c,[a("3 校園軼事篇"),i(t,{type:"warning",text:"未完待續"}),a(),l])])}const g=r(h,[["render",_]]);export{P as __pageData,g as default};
